#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int singleNumber(vector<int>& nums) {
        int result = 0;
        for (int num : nums) {
            result ^= num;
        }
        return result;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int _;
    if (!(cin >> _)) return 0;
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) {
        if (!(cin >> nums[i])) return 0;
    }
    Solution sol;
    int ans = sol.singleNumber(nums);
    cout << ans << endl;
    return 0;
}
